import re

text = """Gregory Lynn Geoffroy is an American higher education administrator and professor of chemistry who served as the 14th president of Iowa State University from 2001 to 2012.
Geoffroy received his BA from the University of Louisville in 1968.  He received his PhD in chemistry from California Institute of Technology in 1974.  Between receiving his two degrees Geoffroy served from 1969 to 1970 in the United States Navy.
He became an assistant professor of chemistry at Pennsylvania State University in 1974 retaining that position until 1978, when he advanced to the rank of Associate Professor which he held until 1982 when he became a full professor.  In 1988 Geoffroy became the head of the Pennsylvania State Chemistry Department.  He only was in this position a year because in 1989 he became dean of the Eberly College of Science at Pennsylvania State.  He retained this position until 1997 when he left Pennsylvania State to serve as Senior vice president for academic affairs and provost at the University of Maryland, College Park.  Geoffroy remained in this last position until he assumed the presidency of Iowa State. After leaving Iowa State he assumed his new role as chairman of the board of trustees at Ashford University."""

# Extract key milestones using regex
milestones = re.findall(r'(?:in|from|until|to)\s+(\d{4})[^\n]*?(?:became|served as|received|earned|advanced to|assumed)', text)

# Format the milestones into a list of tuples (year, description)
formatted_milestones = []
for year in milestones:
    if year == '1968':
        desc = "Earned BA from the University of Louisville"
    elif year == '1969':
        desc = "Served in the United States Navy"
    elif year == '1974':
        desc = "Earned PhD in chemistry from California Institute of Technology and became assistant professor at Pennsylvania State University"
    elif year == '1978':
        desc = "Promoted to Associate Professor at Pennsylvania State University"
    elif year == '1982':
        desc = "Became a full professor at Pennsylvania State University"
    elif year == '1988':
        desc = "Became head of the Pennsylvania State Chemistry Department"
    elif year == '1989':
        desc = "Became dean of the Eberly College of Science at Pennsylvania State University"
    elif year == '1997':
        desc = "Became Senior Vice President for Academic Affairs and Provost at the University of Maryland, College Park"
    elif year == '2001':
        desc = "Became President of Iowa State University"
    elif year == '2012':
        desc = "Left presidency of Iowa State University"
    else:
        continue
    formatted_milestones.append((year, desc))

# Print the formatted milestones
for year, desc in formatted_milestones:
    print(f"{year}: {desc}")
